import re, os

BASE = '/home/archon/FormalizationProjects/Algebraic-Jacobian-Challenge/AlgebraicJacobian/'

def count_sorry_in_code(filepath):
    """Count actual sorry invocations in Lean code (not in comments)."""
    with open(filepath) as f:
        content = f.read()

    # State machine approach: track if we're in a comment
    in_block = 0
    lines = content.split('\n')
    count = 0
    for line in lines:
        i = 0
        while i < len(line):
            if in_block > 0:
                if line[i:i+2] == '-/':
                    in_block -= 1
                    i += 2
                    continue
                elif line[i:i+2] == '/-':
                    in_block += 1
                    i += 2
                    continue
                i += 1
            else:
                if line[i:i+2] == '/-':
                    in_block += 1
                    i += 2
                    continue
                elif line[i:i+2] == '--':
                    # Rest of line is comment
                    break
                else:
                    i += 1
        if in_block == 0:
            # Check the code portion
            code = ''
            j = 0
            b = 0
            while j < len(line):
                if b > 0:
                    if line[j:j+2] == '-/': b -= 1; j += 2; continue
                    elif line[j:j+2] == '/-': b += 1; j += 2; continue
                    j += 1
                else:
                    if line[j:j+2] == '/-': b += 1; j += 2; continue
                    elif line[j:j+2] == '--': break
                    else: code += line[j]; j += 1
            if 'sorry' in code:
                count += 1
        # Handle case where line was partially in block
    return count

files = []
for root, dirs, fnames in os.walk(BASE):
    for fname in fnames:
        if fname.endswith('.lean'):
            files.append(os.path.join(root, fname))
files.sort()

for f in files:
    c = count_sorry_in_code(f)
    rel = f.replace(BASE, '')
    if c > 0:
        print(f'{c:3d} {rel}')
